const e=JSON.parse('{"key":"v-34a19ce8","path":"/infra/auto-scaling/introduce.html","title":"오토 스케일링을 적용하려는 이유","lang":"en-US","frontmatter":{"title":"오토 스케일링을 적용하려는 이유","category":["Infra."],"tag":["AutoScale"],"order":1,"description":"오토 스케일링(Auto Scaling)은 클라우드 컴퓨팅 환경에서 필요에 따라 서비스를 빠르게 확장하거나 서버 자원을 모니터링하여 서버 사이즈를 자동으로 조절하는 서비스를 말한다. 오토 스케일링의 방법에는 크케 스케일 업과 스케일 아웃이 있다. 스케일 업 (Scale Up) 램이 1기가인 컴퓨터를 16기가로 교체하는 것처럼 하드웨어의 성능을 올리는 것을 스케일 업이라고한다. 스케일 아웃 (Scale Out) 이번에 적용해보려는게 스케일 아웃이다. 스케일 아웃은 규모를 늘리는 것이다.","head":[["meta",{"property":"og:url","content":"https://zamoca.space/infra/auto-scaling/introduce.html"}],["meta",{"property":"og:site_name","content":"Zamoca Space"}],["meta",{"property":"og:title","content":"오토 스케일링을 적용하려는 이유"}],["meta",{"property":"og:description","content":"오토 스케일링(Auto Scaling)은 클라우드 컴퓨팅 환경에서 필요에 따라 서비스를 빠르게 확장하거나 서버 자원을 모니터링하여 서버 사이즈를 자동으로 조절하는 서비스를 말한다. 오토 스케일링의 방법에는 크케 스케일 업과 스케일 아웃이 있다. 스케일 업 (Scale Up) 램이 1기가인 컴퓨터를 16기가로 교체하는 것처럼 하드웨어의 성능을 올리는 것을 스케일 업이라고한다. 스케일 아웃 (Scale Out) 이번에 적용해보려는게 스케일 아웃이다. 스케일 아웃은 규모를 늘리는 것이다."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2024-02-12T13:17:41.000Z"}],["meta",{"property":"article:author","content":"추연규"}],["meta",{"property":"article:tag","content":"AutoScale"}],["meta",{"property":"article:modified_time","content":"2024-02-12T13:17:41.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"오토 스케일링을 적용하려는 이유\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2024-02-12T13:17:41.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"추연규\\",\\"url\\":\\"https://github.com/zamoca42\\"}]}"]]},"headers":[{"level":2,"title":"스케일 업 (Scale Up)","slug":"스케일-업-scale-up","link":"#스케일-업-scale-up","children":[]},{"level":2,"title":"스케일 아웃 (Scale Out)","slug":"스케일-아웃-scale-out","link":"#스케일-아웃-scale-out","children":[]},{"level":2,"title":"참고 링크","slug":"참고-링크","link":"#참고-링크","children":[]}],"git":{"createdTime":1707739053000,"updatedTime":1707743861000,"contributors":[{"name":"Chooooooo","email":"suntail2002@naver.com","commits":2}]},"readingTime":{"minutes":0.36,"words":107},"filePathRelative":"infra/auto-scaling/introduce.md","localizedDate":"February 12, 2024","excerpt":"<p>오토 스케일링(Auto Scaling)은 클라우드 컴퓨팅 환경에서 필요에 따라 서비스를 빠르게 확장하거나<br>\\n서버 자원을 모니터링하여 서버 사이즈를 자동으로 조절하는 서비스를 말한다.</p>\\n<p>오토 스케일링의 방법에는 크케 스케일 업과 스케일 아웃이 있다.</p>\\n<h2> 스케일 업 (Scale Up)</h2>\\n<p>램이 1기가인 컴퓨터를 16기가로 교체하는 것처럼 하드웨어의 성능을 올리는 것을 스케일 업이라고한다.</p>\\n<h2> 스케일 아웃 (Scale Out)</h2>\\n<p>이번에 적용해보려는게 스케일 아웃이다. 스케일 아웃은 규모를 늘리는 것이다.</p>","autoDesc":true}');export{e as data};
